PART = '# Generated by Oyen AI Animation Studio V0.4\n# Oyen Purba 3D Rig V1: segmented production-safe armature rig.\n# Run with:\n# blender --background --factory-startup --enable-autoexec --python oyen_blender_scene.py\n\nfrom __future__ import annotations\n\nimport json\nimport math\nimport os\nimport traceback\n\nimport bpy\nfrom mathutils import Vector\n\nJOB = json.loads(r"""__JOB_JSON__""")\nOUTPUT_ROOT = os.path.abspath(\n    os.environ.get(\n        "OYEN_OUTPUT_DIR",\n        os.path.join(os.path.dirname(os.path.abspath(__file__)), "oyen_output"),\n    )\n)\nBLEND_PATH = os.path.join(OUTPUT_ROOT, "oyen_preview.blend")\nVIDEO_PATH = os.path.join(OUTPUT_ROOT, "oyen_preview.mp4")\n\n\ndef log(message: str) -> None:\n    print(f"OYEN_WORKER: {message}")\n\n\ndef rgba(hex_color: str, alpha: float = 1.0) -> tuple[float, float, float, float]:\n    value = hex_color.strip().lstrip("#")\n    return (\n        int(value[0:2], 16) / 255.0,\n        int(value[2:4], 16) / 255.0,\n        int(value[4:6], 16) / 255.0,\n        alpha,\n    )\n\n\ndef clear_scene() -> None:\n    if bpy.context.object and bpy.context.object.mode != "OBJECT":\n        bpy.ops.object.mode_set(mode="OBJECT")\n    bpy.ops.object.select_all(action="SELECT")\n    bpy.ops.object.delete(use_global=False)\n    for datablocks in (\n        bpy.data.meshes,\n        bpy.data.curves,\n        bpy.data.materials,\n        bpy.data.armatures,\n        bpy.data.cameras,\n        bpy.data.lights,\n    ):\n        for datablock in list(datablocks):\n            if datablock.users == 0:\n                datablocks.remove(datablock)\n\n\ndef make_material(\n    name: str,\n    color: tuple[float, float, float, float],\n    roughness: float = 0.62,\n    metallic: float = 0.0,\n):\n    material = bpy.data.materials.new(name=name)\n    material.diffuse_color = color\n    material.use_nodes = True\n    bsdf = material.node_tree.nodes.get("Principled BSDF")\n    if bsdf:\n        bsdf.inputs["Base Color"].default_value = color\n        bsdf.inputs["Roughness"].default_value = roughness\n        bsdf.inputs["Metallic"].default_value = metallic\n    return material\n\n\ndef smooth_object(obj) -> None:\n    if obj.type == "MESH":\n        for polygon in obj.data.polygons:\n            polygon.use_smooth = True\n\n\ndef add_uv_sphere(name, location, scale, material, segments=20, rings=12):\n    bpy.ops.mesh.primitive_uv_sphere_add(\n        segments=segments,\n        ring_count=rings,\n        location=location,\n    )\n    obj = bpy.context.active_object\n    obj.name = name\n    obj.scale = scale\n    bpy.ops.object.transform_apply(location=False, rotation=False, scale=True)\n    obj.data.materials.append(material)\n    smooth_object(obj)\n    return obj\n\n\ndef add_cube(name, location, scale, material, rotation=(0.0, 0.0, 0.0), bevel=0.08):\n    bpy.ops.mesh.primitive_cube_add(location=location, rotation=rotation)\n    obj = bpy.context.active_object\n    obj.name = name\n    obj.scale = scale\n    bpy.ops.object.transform_apply(location=False, rotation=False, scale=True)\n    obj.data.materials.append(material)\n    if bevel > 0:\n        modifier = obj.modifiers.new(name="Soft edges", type="BEVEL")\n        modifier.width = bevel\n        modifier.segments = 2\n    return obj\n\n\n'